import os
import json
import redis
from typing import Optional, Dict, Any, List

class JuraProtocol:
    """
    Jura Atomic Chat Reconfiguration Protocol
    - Hot-swap system prompts mid-conversation
    - Inject user/assistant context on the fly
    - Redis-backed state
    """
    def __init__(self, redis_host: str = "10.85.19.187", redis_port: int = 6379):
        try:
            self.redis = redis.Redis(host=redis_host, port=redis_port, db=0, socket_connect_timeout=1)
            self.redis.ping()
            self.use_redis = True
        except:
            print("Warning: Redis connection failed, falling back to local state.")
            self.use_redis = False
            self.local_state = {}

        self.current_system_prompt = ""
        self.active_commands = set()
        self._load_cursorrules()

    def _load_cursorrules(self):
        """Auto-loads .cursorrules if present"""
        try:
            if os.path.exists(".cursorrules"):
                with open(".cursorrules", "r") as f:
                    self.cursor_rules = f.read()
            else:
                self.cursor_rules = ""
        except Exception as e:
            print(f"Failed to load .cursorrules: {e}")
            self.cursor_rules = ""

    def inject_system_prompt(self, prompt: str) -> 'JuraProtocol':
        """Hot-swap system prompts mid-conversation"""
        self.current_system_prompt = prompt
        if self.use_redis:
            self.redis.set("jura:system_prompt", prompt)
        return self

    def activate_command(self, command: str) -> 'JuraProtocol':
        """Activate a specific command protocol"""
        self.active_commands.add(command)
        if self.use_redis:
            self.redis.sadd("jura:active_commands", command)
        return self

    def evaluate_with_context(self, query: str) -> Dict[str, Any]:
        """Evaluate a query with the current injected context"""
        context = {
            "system_prompt": self.current_system_prompt,
            "active_commands": list(self.active_commands),
            "cursor_rules": self.cursor_rules,
            "query": query
        }
        # In a real implementation, this might call an LLM or logic engine
        # For now, we return the assembled context for the orchestrator
        return {
            "status": "evaluated",
            "context": context,
            "safety_check": "PASSED" if "musk-filter" in self.active_commands else "UNVERIFIED"
        }

    def get_state(self) -> Dict[str, Any]:
        if self.use_redis:
            return {
                "system_prompt": self.redis.get("jura:system_prompt"),
                "active_commands": [x.decode() for x in self.redis.smembers("jura:active_commands")]
            }
        return {
            "system_prompt": self.current_system_prompt,
            "active_commands": list(self.active_commands)
        }

